{
	var structs []Struct
	for _, t := range docPkg.Types {
		if t == nil || t.Decl == nil {
			return nil, errors.New("t or t.Decl is nil")
		}
		for _, spec := range t.Decl.Specs {
			typeSpec, ok := spec.(*ast.TypeSpec)
			if !ok {
				return nil, errors.New("not a *ast.TypeSpec")
			}
			structType, ok := typeSpec.Type.(*ast.StructType)
			if ok {
				parsedStruct := Struct{Name: t.Name, Fields: make([]Field, 0, len(structType.Fields.List)), Docs: getDocsForStruct(t.Doc), Methods: make([]Method, 0), IsExported: ast.IsExported(t.Name), PtrPackage: &ourPkg}
				var defBuf bytes.Buffer
				defBuf.WriteString(fmt.Sprintf("type %s struct {\n", t.Name))
				for _, field := // Generate the full struct definition using AST
				range structType.Fields.List {
					defBuf.WriteString("\t")
					for i, name := range field.Names {
						if i > 0 {
							defBuf.WriteString(", ")
						}
						defBuf.WriteString(name.Name)
					}
					if len(field.Names) > 0 {
						defBuf.WriteString(" ")
					}
					defBuf.WriteString(exprToString(field.Type))
					if field.Tag != nil {
						defBuf.WriteString(" ")
						defBuf.WriteString(field.Tag.Value)
					}
					if field.Comment != nil && len(field.Comment.List) > 0 {
						defBuf.WriteString(" ")
						defBuf.WriteString(field.Comment.List[0].Text)
					}
					defBuf.WriteString("\n")
				}
				defBuf.WriteString("}")
				parsedStruct.Definition = defBuf.String()
				for _, fvalue := range structType.Fields.List {
					name := ""
					if len(fvalue.Names) > 0 {
						name = fvalue.Names[0].Obj.Name
					}
					field := Field{Name: name, Type: "", Tag: "", TypeDetails: TypeDetails{}}
					if len(field.Name) > 0 {
						field.Private = strings.ToLower(string(field.Name[0])) == string(field.Name[0])
					}
					if fvalue.Doc != nil {
						field.Docs = getDocsForFieldAst(fvalue.Doc)
					}
					if fvalue.Comment != nil {
						field.Comment = cleanDocText(fvalue.Comment.Text())
					}
					if fvalue.Tag != nil {
						field.Tag = strings.Trim(fvalue.Tag.Value, "`")
					}
					typeDetails, err := getFullType(fvalue.Type, ourPkg)
					if err != nil {
						return nil, err
					}
					field.TypeDetails = *typeDetails
					field.Pointer = typeDetails.IsPointer
					field.Slice = typeDetails.IsSlice
					field.Type = typeDetails.TypeName
					parsedStruct.Fields = append(parsedStruct.Fields, field)
				}
				structs = append(structs, parsedStruct)
			}
		}
	}
	return structs, nil
}

{
	var interfaces []Interface
	for _, t := range docPkg.Types {
		if t == nil || t.Decl == nil {
			return nil, errors.New("t or t.Decl is nil")
		}
		for _, spec := range t.Decl.Specs {
			typeSpec, ok := spec.(*ast.TypeSpec)
			if !ok {
				return nil, errors.New("not a *ast.TypeSpec")
			}
			interfaceType, ok := typeSpec.Type.(*ast.InterfaceType)
			if ok {
				parsedInterface := Interface{Name: t.Name, Methods: make([]Method, 0), Docs: getDocsForStruct(t.Doc), IsExported: ast.IsExported(t.Name), PtrPackage: &pkg}
				var defBuf bytes.Buffer
				defBuf.WriteString(fmt.Sprintf("type %s interface {\n", t.Name))
				for _, m := // Generate the full interface definition
				range interfaceType.Methods.List {
					if funcType, ok := m.Type.(*ast.FuncType); ok {
						methodDef := m.Names[0].Name + "(" + formatParams(funcType.Params, pkg) + ")"
						if funcType.Results != nil && len(funcType.Results.List) > 0 {
							returnStr := formatParams(funcType.Results, pkg)
							if len(funcType.Results.List) > 1 {
								methodDef += " (" + returnStr + ")"
							} else {
								methodDef += " " + returnStr
							}
						}
						methodName := m.Names[0].Name
						method := Method{Name: methodName, Params: extractParams(funcType.Params, pkg), Returns: extractParams(funcType.Results, pkg), Docs: getDocsForFieldAst(m.Doc), Signature: fmt.Sprintf("%s(%s) (%s)", methodName, formatParams(funcType.Params, pkg), formatParams(funcType.Results, pkg)), Definition: methodDef, IsExported: ast.IsExported(methodName), IsTest: isTestFunction(methodName), IsBenchmark: isBenchmarkFunction(methodName)}
						defBuf.WriteString("\t")
						defBuf.WriteString(m.Names[0].Name)
						defBuf.WriteString("(")
						defBuf.WriteString(formatParams(funcType.Params, pkg))
						defBuf.WriteString(")")
						if funcType.Results != nil && len(funcType.Results.List) > 0 {
							defBuf.WriteString(" ")
							returnStr := formatParams(funcType.Results, pkg)
							if len(funcType.Results.List) > 1 {
								defBuf.WriteString("(")
								defBuf.WriteString(returnStr)
								defBuf.WriteString(")")
							} else {
								defBuf.WriteString(returnStr)
							}
						}
						defBuf.WriteString("\n")
						parsedInterface.Methods = append(parsedInterface.Methods, method)
					}
				}
				defBuf.WriteString("}")
				parsedInterface.Definition = defBuf.String()
				interfaces = append(interfaces, parsedInterface)
			}
		}
	}
	return interfaces, nil
}

