{
	var constants []Constant
	var variables []Variable
	for _, file := range pkg.Files {
		for _, decl := range file.Decls {
			genDecl, ok := decl.(*ast.GenDecl)
			if !ok {
				continue
			}
			switch genDecl.Tok {
			case token.CONST:
				for _, spec := range genDecl.Specs {
					valSpec, ok := spec.(*ast.ValueSpec)
					if !ok {
						continue
					}
					for i, name := range valSpec.Names {
						constant := Constant{Name: name.Name, Value: "", Docs: getDocsForFieldAst(valSpec.Doc)}
						if i < len(valSpec.Values) {
							constant.Value = exprToString(valSpec.Values[i])
						}
						constants = append(constants, constant)
					}
				}
			case token.VAR:
				for _, spec := range genDecl.Specs {
					valSpec, ok := spec.(*ast.ValueSpec)
					if !ok {
						continue
					}
					for _, name := range valSpec.Names {
						varType := ""
						if valSpec.Type != nil {
							tmp, _ := getFullType(valSpec.Type, ourPkg)
							varType = tmp.TypeName
						}
						variable := Variable{Name: name.Name, Type: varType, Docs: getDocsForFieldAst(valSpec.Doc)}
						variables = append(variables, variable)
					}
				}
			}
		}
	}
	return constants, variables, nil
}

